@namespace Lumeo

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <button type="button"
            class="@($"inline-flex {ControlSizeClass} items-center justify-center rounded-s-md border border-e-0 {(EffectiveInvalid ? "border-destructive" : "border-border/60")} bg-muted text-muted-foreground transition-colors hover:bg-muted/80 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:relative focus-visible:z-10 disabled:pointer-events-none disabled:opacity-50")"
            disabled="@(Disabled || IsAtMin)"
            @onclick="Decrement"
            aria-label="@L["NumberInput.Decrease"]">
        <SvgGlyph Svg="@(LumeoIcons.Minus)" class="h-4 w-4" />
    </button>
    <div class="@($"relative {(Block ? "flex flex-1" : "inline-flex")} items-center {HeightClass} border {(EffectiveInvalid ? "border-destructive" : "border-border/60")} bg-background")">
        @if (!string.IsNullOrEmpty(Prefix))
        {
            <span class="ps-2 text-sm text-muted-foreground select-none">@Prefix</span>
        }
        <input @ref="_inputRef"
               type="number"
               name="@Name"
               id="@FormFieldControlId"
               aria-required="@Required.ToString().ToLowerInvariant()"
               aria-invalid="@EffectiveInvalid.ToString().ToLowerInvariant()"
               aria-label="@EffectiveAriaLabel"
               aria-describedby="@FormFieldDescribedBy"
               class="@($"{HeightClass} {(Block ? "w-full min-w-0" : "w-20")} bg-transparent {(string.IsNullOrEmpty(Prefix) && string.IsNullOrEmpty(Suffix) ? "px-3" : "px-1")} {(Block ? "text-start" : "text-center")} text-sm text-foreground outline-none [appearance:textfield] [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none")"
               value="@DisplayValue"
               disabled="@Disabled"
               min="@Min"
               max="@Max"
               step="@Step"
               @onchange="OnInputChange"
               @onkeydown="HandleKeyDown"
               @onwheel="HandleWheel"
               @onwheel:preventDefault="@UseMouseWheel" />
        @if (!string.IsNullOrEmpty(Suffix))
        {
            <span class="pe-2 text-sm text-muted-foreground select-none">@Suffix</span>
        }
    </div>
    <button type="button"
            class="@($"inline-flex {ControlSizeClass} items-center justify-center rounded-e-md border border-s-0 {(EffectiveInvalid ? "border-destructive" : "border-border/60")} bg-muted text-muted-foreground transition-colors hover:bg-muted/80 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:relative focus-visible:z-10 disabled:pointer-events-none disabled:opacity-50")"
            disabled="@(Disabled || IsAtMax)"
            @onclick="Increment"
            aria-label="@L["NumberInput.Increase"]">
        <SvgGlyph Svg="@(LumeoIcons.Plus)" class="h-4 w-4" />
    </button>
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    /// <summary>The current numeric value; null when empty.</summary>
    [Parameter] public double? Value { get; set; }

    /// <summary>Two-way callback for <see cref="Value"/>.</summary>
    [Parameter] public EventCallback<double?> ValueChanged { get; set; }

    /// <summary>Lower bound; typed/stepped values are clamped to it. Null means no lower bound.</summary>
    [Parameter] public double? Min { get; set; }

    /// <summary>Upper bound; typed/stepped values are clamped to it. Null means no upper bound.</summary>
    [Parameter] public double? Max { get; set; }

    /// <summary>Amount added/subtracted per +/- click, ArrowUp/ArrowDown, or mouse-wheel tick. Default <c>1</c>.</summary>
    [Parameter] public double Step { get; set; } = 1;

    /// <summary>Number of decimal places the value is rounded to on every change. Null leaves fractional precision unrounded (except for FP cleanup on stepped values).</summary>
    [Parameter] public int? Precision { get; set; }

    /// <summary>Disables the input and both stepper buttons. Default <c>false</c>.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>Enables incrementing/decrementing by scrolling the mouse wheel over the input. Default <c>false</c>.</summary>
    [Parameter] public bool UseMouseWheel { get; set; }

    /// <summary>Text rendered inside the input before the value (e.g. a currency symbol).</summary>
    [Parameter] public string? Prefix { get; set; }

    /// <summary>Text rendered inside the input after the value (e.g. a unit).</summary>
    [Parameter] public string? Suffix { get; set; }

    /// <summary>
    /// Culture used to parse typed input. Display of the value inside the native
    /// <c>&lt;input type="number"&gt;</c> element uses <see cref="System.Globalization.CultureInfo.InvariantCulture"/>
    /// because HTML5 requires period-as-decimal — browsers will not accept a comma decimal
    /// in this input type. Leave null to honour ASP.NET request localization for parsing
    /// (lets a <c>de-DE</c> user paste <c>1,5</c> and have it round-trip to <c>1.5</c>).
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;

    /// <summary>Marks the field as required, rendering a trailing asterisk on the label and setting <c>aria-required</c>. Default <c>false</c>.</summary>
    [Parameter] public bool Required { get; set; }

    /// <summary>Forces the invalid (error) visual state and <c>aria-invalid</c>, independent of any ancestor <c>FormField</c>. Default <c>false</c>.</summary>
    [Parameter] public bool Invalid { get; set; }

    /// <summary>Error text shown below the control when invalid (outside a <c>FormField</c>) and not inside a <c>FormField</c>.</summary>
    [Parameter] public string? ErrorText { get; set; }

    /// <summary>Helper text shown below the control when not invalid and not inside a <c>FormField</c>.</summary>
    [Parameter] public string? HelperText { get; set; }

    /// <summary>Label text rendered above the control (unless the control is inside a <c>FormField</c>, which renders its own label).</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>Explicit accessible name for the input, taking priority over <see cref="Label"/> when both are set.</summary>
    [Parameter] public string? AriaLabel { get; set; }

    /// <summary>The <c>name</c> attribute for form submission.</summary>
    [Parameter] public string? Name { get; set; }
    /// <summary>Focuses the underlying number &lt;input&gt; on first render.
    /// See <c>Input.AutoFocus</c> for why the HTML <c>autofocus</c> attribute
    /// doesn't work in Blazor WASM.</summary>
    [Parameter] public bool AutoFocus { get; set; }
    /// <summary>Per-control density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Only the control height shifts
    /// between values.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    /// <summary>Additional CSS classes merged onto the control's outer wrapper.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes splatted onto the control's outer wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private ElementReference _inputRef;

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    // Height tracks density; Comfortable reproduces the historical h-9.
    private string HeightClass => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "h-8",
        Lumeo.Density.Spacious => "h-10",
        _ => "h-9"
    };

    // Stepper buttons stay square so the +/- glyphs remain centred.
    private string ControlSizeClass => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "h-8 w-8",
        Lumeo.Density.Spacious => "h-10 w-10",
        _ => "h-9 w-9"
    };

    /// <summary>The underlying number &lt;input&gt; element.</summary>
    public ElementReference Element => _inputRef;

    /// <summary>Programmatically move focus to the input.</summary>
    public ValueTask FocusAsync() => _inputRef.FocusAsync();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && AutoFocus)
        {
            try { await _inputRef.FocusAsync(); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Screen readers need an accessible name on the <input type="number"> even when the
    // visible label is rendered as a sibling element rather than a <label for="..."> wrapper.
    // Priority: explicit AriaLabel > Label parameter > FormField label context.
    private string? EffectiveAriaLabel => !string.IsNullOrEmpty(AriaLabel) ? AriaLabel : Label;

    // Adopt the FormField's generated id + describedby so the field's <label for>
    // resolves to this input and aria-describedby points at the help/error text
    // (Base UI Field a11y). Null outside a FormField — the id/aria attributes are
    // then omitted, and a consumer-set id via AdditionalAttributes still wins
    // (it splats after these). Empty guard avoids id="" if no id was generated.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    /// <summary>Stretch the control to fill its container — a full-width input between the
    /// −/+ buttons — instead of sizing to its content. Use it in form layouts so the field
    /// lines up with sibling full-width inputs/selects (the LumeoForm generator sets it).</summary>
    [Parameter] public bool Block { get; set; }

    private string CssClass => Cx.Merge(Block ? "flex w-full items-center" : "inline-flex items-center", Class);

    private bool IsAtMin => Min.HasValue && Value.HasValue && Value.Value <= Min.Value;
    private bool IsAtMax => Max.HasValue && Value.HasValue && Value.Value >= Max.Value;

    private string DisplayValue
    {
        get
        {
            if (Value is null) return "";
            if (Precision.HasValue)
                return Value.Value.ToString($"F{Precision.Value}", System.Globalization.CultureInfo.InvariantCulture);
            return Value.Value.ToString(System.Globalization.CultureInfo.InvariantCulture);
        }
    }

    private async Task Increment()
    {
        var newValue = RoundStepped((Value ?? 0) + Step);
        await SetValue(newValue);
    }

    private async Task Decrement()
    {
        var newValue = RoundStepped((Value ?? 0) - Step);
        await SetValue(newValue);
    }

    // Stepping a binary double by a fractional Step (e.g. 0.1) accumulates FP error
    // (0.1 + 0.2 -> 0.30000000000000004), which DisplayValue then prints verbatim
    // because rounding only happens when Precision is set (#156). When Precision is
    // null, snap the stepped result to Step's own decimal scale so successive +/-
    // stay clean; when Precision is set, SetValue already rounds so this is a no-op.
    private double RoundStepped(double value)
    {
        if (Precision.HasValue) return value;
        var digits = StepDecimalDigits();
        return digits == 0 ? value : Math.Round(value, digits, MidpointRounding.AwayFromZero);
    }

    // Number of fractional digits in Step (clamped to the double-safe 0..15 range
    // Math.Round accepts), derived from its invariant round-trip representation.
    private int StepDecimalDigits()
    {
        var s = Step.ToString("R", System.Globalization.CultureInfo.InvariantCulture);
        var dot = s.IndexOf('.');
        if (dot < 0 || s.IndexOf('E') >= 0 || s.IndexOf('e') >= 0) return 0;
        return Math.Min(s.Length - dot - 1, 15);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (Disabled) return;
        switch (e.Key)
        {
            case "ArrowUp":
                await Increment();
                break;
            case "ArrowDown":
                await Decrement();
                break;
        }
    }

    private async Task HandleWheel(WheelEventArgs e)
    {
        if (!UseMouseWheel || Disabled) return;
        if (e.DeltaY < 0)
            await Increment();
        else if (e.DeltaY > 0)
            await Decrement();
    }

    private async Task OnInputChange(ChangeEventArgs e)
    {
        var raw = e.Value?.ToString();

        // Empty / whitespace clears the field to null. Without this the failed
        // parse below short-circuited and the value got stuck at its last number,
        // so the control could never be emptied (#176).
        if (string.IsNullOrWhiteSpace(raw))
        {
            await SetValue(null);
            return;
        }

        // Parse order is decided by the decimal separator actually present in the
        // string. The native <input type="number"> reports an invariant '.' decimal,
        // but a consumer rendering via FormatType=Text (or pasting) can deliver a
        // culture-formatted value such as the de-DE "1,5". If the effective culture's
        // decimal separator is a comma and the string contains one, parse with the
        // culture FIRST — otherwise an invariant parse would read "1,5" as the integer
        // 15 (comma = thousands) and the comma decimal would never round-trip (#176).
        var cultureDecimal = EffectiveCulture.NumberFormat.NumberDecimalSeparator;
        var preferCulture = cultureDecimal != "." && raw.Contains(cultureDecimal, StringComparison.Ordinal);

        bool ok;
        double parsed;
        if (preferCulture)
        {
            ok = double.TryParse(raw, System.Globalization.NumberStyles.Any, EffectiveCulture, out parsed)
                || double.TryParse(raw, System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out parsed);
        }
        else
        {
            ok = double.TryParse(raw, System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out parsed)
                || double.TryParse(raw, System.Globalization.NumberStyles.Any, EffectiveCulture, out parsed);
        }

        if (ok)
        {
            await SetValue(parsed);
        }
    }

    private async Task SetValue(double? newValue)
    {
        if (newValue is null)
        {
            if (Value is null) return;
            Value = null;
            await ValueChanged.InvokeAsync(null);
            return;
        }

        var v = newValue.Value;
        if (Min.HasValue && v < Min.Value) v = Min.Value;
        if (Max.HasValue && v > Max.Value) v = Max.Value;

        if (Precision.HasValue)
        {
            v = Math.Round(v, Precision.Value);
        }

        Value = v;
        await ValueChanged.InvokeAsync(Value);
    }
}
